#include <string>
#include <iostream>

int main() {
    std::string text = "  hello world  ";

    // قطع المسافات البادئة يدويًا
    auto start = text.find_first_not_of(' ');
    if (start != std::string::npos) {
        text = text.substr(start); // "hello world  "
    }

    // قطع المسافات اللاحقة
    auto end = text.find_last_not_of(' ');
    if (end != std::string::npos) {
        text = text.substr(0, end + 1); // "hello world"
    }

    std::cout << '[' << text << ']'; // [hello world]

    // ملاحظة: في C++20 استخدم trim أو تنفيذ يدوي أفضل
}

