#include <string>
#include <iostream>

int main() {
    std::string s = "aXbXcX";

    // erase(iterator) يُزيل حرفًا واحدًا في الموضع المُشار إليه
    for (auto it = s.begin(); it != s.end(); ) {
        if (*it == 'X') {
            it = s.erase(it); // erase يُرجع مكرّر للعنصر التالي
        } else {
            ++it;
        }
    }
    std::cout << s; // abc
}

#include <string>
#include <algorithm>
#include <iostream>

int main() {
    std::string s = "h e l l o   w o r l d";

    // remove_if يُعيد ترتيب: ينقل ما نريد حذفه للنهاية
    // erase يُزيل هذا الجزء من النهاية
    s.erase(
        std::remove_if(s.begin(), s.end(), [](char c) { return c == ' '; }),
        s.end()
    );
    std::cout << s; // helloworld

    // لماذا لا نستخدم erase وحدها؟
    // لأن erase(pos, count) يحتاج موضعًا وليس شرطًا
    // remove_if يحوّل الشرط إلى موضع واحد (بداية الجزء المراد حذفه)
}

