#include <string>
#include <iostream>

void replace_all(std::string& s, const std::string& from, const std::string& to) {
    if (from.empty()) return; // منع حلقة لا نهائية
    size_t pos = 0;
    while ((pos = s.find(from, pos)) != std::string::npos) {
        s.replace(pos, from.size(), to);
        pos += to.size(); // تخطي الجزء المستبدل لمنع حلقة لا نهائية
    }
}

int main() {
    std::string text = "red blue red green red";
    replace_all(text, "red", "yellow");
    std::cout << text; // yellow blue yellow green yellow
}

