#include <string>
#include <iostream>

int main() {
    std::string line = "hello world\n";

    // نمط شائع جدًا: إزالة trailing newline
    if (!line.empty() && line.back() == '\n') {
        line.pop_back(); // يُزيل آخر حرف
    }
    std::cout << '[' << line << ']'; // [hello world]

    // التعامل مع \r\n (Windows)
    if (!line.empty() && line.back() == '\r') {
        line.pop_back();
    }
}

