    // a.compare(b) != 0 — مختلفان!

    // ✅ مقارنة غير حساسة: حوّل ثم قارن
    auto to_lower = [](std::string s) {
        std::transform(s.begin(), s.end(), s.begin(),
                       [](unsigned char c) { return std::tolower(c); });
        return s;
    };

    if (to_lower(a).compare(to_lower(b)) == 0) {
        std::cout << "متساويان بغض النظر عن الحالة\n";
    }

    // أو استخدم equal مع custom comparator — أنسب أداءً لأنه لا يُنشئ نسخًا
    bool same = std::equal(a.begin(), a.end(), b.begin(), b.end(),
        [](char x, char y) { return std::tolower(x) == std::tolower(y); });
}

