    // - النطاق الفارغ (سلسلة فارغة) يحتاج استثناء
    // - begin() == end() لا يعني 'فارغ'

    // مع past-the-end:
    // - الحلقات موحدة: while (it != end) { process(*it); ++it; }
    // - النطاق الفارغ: begin() == end() — سلسلة فارغة
