    // هذا التصميم موحد في كل C++: string, vector, array, list...
    std::cout << "size: " << (s.end() - s.begin()) << '\n'; // 3

    std::string empty;
    std::cout << "empty: " << (empty.begin() == empty.end()) << '\n'; // 1 (true)
}

