#include <string>
#include <iostream>

std::string trim(const std::string& s) {
    // 1. إيجاد أول حرف ليس مسافة بيضاء
    auto start = s.find_first_not_of(" \t\n\r");
    if (start == std::string::npos) return ""; // كلها مسافات

    // 2. إيجاد آخر حرف ليس مسافة بيضاء
    auto end = s.find_last_not_of(" \t\n\r");

    // 3. استخراج الجزء النظيف
    return s.substr(start, end - start + 1);
}

int main() {
    std::cout << '[' << trim("  hello  ") << ']' << '\n';   // [hello]
    std::cout << '[' << trim("\t\nhello\n\t") << ']' << '\n'; // [hello]
    std::cout << '[' << trim("   ") << ']' << '\n';           // []
}

