#include <string>
#include <iostream>

bool safe_resize(std::string& s, size_t requested) {
    // فحص نظري أولي — لا يضمن نجاح التخصيص
    if (requested > s.max_size()) {
        std::cout << "الطلب يتجاوز الحد النظري\n";
        return false;
    }

    // الفحص الحقيقي: try-catch لأن الذاكرة قد لا تكفي
    try {
        s.resize(requested);
        return true;
    } catch (const std::bad_alloc&) {
        std::cout << "لا توجد ذاكرة كافية\n";
        return false;
    }
}

